AbiParameter.signature:
type = {
  name: string;
  type: string;
  internalType?: string;
  indexed?: boolean;
  components?: AbiParameter[];
}

ContractChange.signature:
type = | { kind: 'contract-added'; name: string; contract: ContractSnapshot }
  | { kind: 'contract-removed'; name: string; contract: ContractSnapshot }
  | { kind: 'contract-modified'; name: string; fragments: FragmentChange[] }

DemoResult.signature:
type = {
  name: string;
  command: string;
  passed: boolean;
  exitCode: number;
  durationMs: number;
  output: string;
}

DocChange.signature:
type = | { kind: 'doc-added'; file: string }
  | { kind: 'doc-removed'; file: string }
  | { kind: 'snippet-broken'; file: string; snippet: DocSnippet }
  | { kind: 'snippet-fixed'; file: string; snippet: DocSnippet }
  | { kind: 'snippet-removed'; file: string; snippet: DocSnippet }
  | { kind: 'snippet-added-broken'; file: string; snippet: DocSnippet }

Finding.signature:
type = {
  ruleId: RuleId;
  severity: 'error' | 'warning';
  layer: Layer;
  message: string;
  file?: string;
  line?: number;
  before?: string;
  after?: string;
}

FragmentChange.signature:
type = | { kind: 'fragment-added'; key: string; fragment: AbiFragment }
  | { kind: 'fragment-removed'; key: string; fragment: AbiFragment }
  | { kind: 'mutability-tightened'; key: string; before: Mutability; after: Mutability }
  | { kind: 'mutability-relaxed'; key: string; before: Mutability; after: Mutability }
  | { kind: 'outputs-changed'; key: string; before: AbiParameter[]; after: AbiParameter[] }

Report.signature:
type = {
  findings: Finding[];
  errorCount: number;
  warningCount: number;
  exitCode: 0 | 1;
}

SdkChange.signature:
type = | { kind: 'export-added'; name: string; export: SdkExport }
  | { kind: 'export-removed'; name: string; export: SdkExport }
  | { kind: 'kind-changed'; name: string; before: SdkExport; after: SdkExport }
  | { kind: 'signature-changed'; name: string; before: SdkExport; after: SdkExport }
